embeds.description:
Por supuesto, aquí tienes un ejemplo en JavaScript (Node.js) usando Afip SDK, donde se agregan percepciones en el campo `Tributos`:

```javascript
const Afip = require('@afipsdk/afip.js');

const date = new Date(Date.now() - ((new Date()).getTimezoneOffset() * 60000)).toISOString().split('T')[0];

const data = {
  'CantReg': 1,
  'PtoVta': 1,
  'CbteTipo': 6,
  'Concepto': 1,
  'DocTipo': 80,
  'DocNro': 20111111112,
  'CbteDesde': 1,
  'CbteHasta': 1,
  'CbteFch': parseInt(date.replace(/-/g, '')),
  'ImpTotal': 200,
  'ImpTotConc': 0,
  'ImpNeto': 150,
  'ImpOpEx': 0,
  'ImpIVA': 21,
  'ImpTrib': 29, // Suma de percepciones
  'MonId': 'PES',
  'MonCotiz': 1,
  'Iva': [
    { 'Id': 5, 'BaseImp': 150, 'Importe': 21 }
  ],
  'Tributos': [
    {
      'Id': 99, // Otro tributo
      'Desc': 'Percepción IIBB',
      'BaseImp': 150,
      'Alic': 5.2,
      'Importe': 7.8
    },
    {
      'Id': 1, // Impuestos nacionales
      'Desc': 'Percepción IVA',
      'BaseImp': 150,
      'Alic': 14,
      'Importe': 21.2
    }
  ]
};

const afip = new Afip({ CUIT: 20111111112 });

afip.ElectronicBilling.createVoucher(data).then(res => {
  console.log(res);
});
```
Este ejemplo está basado en el [ejemplo oficial de afip.js](https://github.com/AfipSDK/afip.js/blob/master/examples/createVoucher.js).

¿Necesitás que te explique algún campo en particular?

